import { mkdir, readFile, writeFile } from "node:fs/promises";
import path from "node:path";

const root = new URL(".", import.meta.url);
const inputPath = new URL("openapi.json", root);
const outputPath = new URL("generated/effect-schemas.ts", root);

const document = JSON.parse(await readFile(inputPath, "utf8"));
const schemas = document.components?.schemas ?? {};

const lines = [
  "// Generated by scratchpad/sdk-schema-generator-spike/generate-effect-schemas.mjs",
  "// Spike output only; do not edit by hand.",
  'import { Schema } from "effect"',
  ""
];

for (const [name, schema] of Object.entries(schemas)) {
  lines.push(`export const ${name}Schema = ${renderSchema(schema)}`);
  lines.push(`export type ${name} = typeof ${name}Schema.Type`);
  lines.push("");
}

await mkdir(path.dirname(outputPath.pathname), { recursive: true });
await writeFile(outputPath, `${lines.join("\n")}\n`);

function renderSchema(schema) {
  if (schema.$ref) {
    return `${refName(schema.$ref)}Schema`;
  }

  if (Array.isArray(schema.type)) {
    const nonNullTypes = schema.type.filter((type) => type !== "null");
    if (nonNullTypes.length === 1 && schema.type.includes("null")) {
      return `Schema.NullOr(${renderSchema({ ...schema, type: nonNullTypes[0] })})`;
    }
  }

  if (schema.enum) {
    if (schema.enum.length === 1) {
      return `Schema.Literal(${JSON.stringify(schema.enum[0])})`;
    }

    return `Schema.Literals([${schema.enum.map((value) => JSON.stringify(value)).join(", ")}])`;
  }

  switch (schema.type) {
    case "object":
      return renderObject(schema);
    case "array":
      return `Schema.Array(${renderSchema(schema.items ?? {})})`;
    case "integer":
    case "number":
      return "Schema.Number";
    case "boolean":
      return "Schema.Boolean";
    case "string":
      return "Schema.String";
    case "null":
      return "Schema.Null";
    default:
      throw new Error(`Unsupported schema: ${JSON.stringify(schema)}`);
  }
}

function renderObject(schema) {
  const required = new Set(schema.required ?? []);
  const entries = Object.entries(schema.properties ?? {}).map(([propertyName, propertySchema]) => {
    const rendered = renderSchema(propertySchema);
    const field = required.has(propertyName)
      ? rendered
      : `Schema.optionalKey(${rendered})`;

    return `  ${JSON.stringify(propertyName)}: ${field}`;
  });

  return `Schema.Struct({\n${entries.join(",\n")}\n})`;
}

function refName(ref) {
  const prefix = "#/components/schemas/";
  if (!ref.startsWith(prefix)) {
    throw new Error(`Unsupported ref: ${ref}`);
  }

  return ref.slice(prefix.length);
}
